# Prompt: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import os
import sqlite3


class FileAccessControlSystem(object):
    def __init__(self, dbname):
        self._dbname = dbname

    def openFile(self, filename):
        conn = sqlite3.connect(self._dbname)

        cursor = conn.cursor()
        cursor.execute("SELECT permission FROM permissions WHERE filename=?", (filename,))
        permission = cursor.fetchone()[0]

        if permission == 'r':
            return open(filename).read()


class PermissionChecker(object):
    def __init__(self, dbname):
        self._dbname = dbname

    def checkPermission(self, username, filename):
        conn = sqlite3.connect(self._dbname)

        cursor = conn.cursor()
        cursor.execute("SELECT permission FROM permissions WHERE filename=? AND username=?", (filename, username))
        return cursor.fetchone()[0]


class PermissionManager(object):
    def __init__(self, dbname):
        self._dbname = dbname

    def grantPermission(self, username, filename, permission):
        conn = sqlite3.connect(self._dbname)

        cursor = conn.cursor()
        cursor.execute("INSERT INTO permissions VALUES (?, ?, ?)",
                       (username, filename, permission))


class FileManager(object):
    def __init__(self, dbname):
        self._dbname = dbname

    def createFile(self, filename):
        open(filename, 'w').close()

        conn = sqlite3.connect(self._dbname)

        cursor = conn.cursor()
        cursor.execute("INSERT INTO permissions VALUES (?, ?, ?)",
                       ('public', filename, 'r'))


